// GC step / tuning constants  (lgc.c, lgc.h)
// ---------------------------------------------------------------------------

/// C: `#define GCSWEEPMAX 100`
const GC_SWEEP_MAX: i32 = 100;

/// C: `#define GCFINMAX 10`
const GC_FIN_MAX: i32 = 10;

/// C: `#define GCFINALIZECOST 50`
const GC_FINALIZE_COST: usize = 50;

