532	    // C: global_State *g = G(L);
533	    // C: lua_assert(isblack(o) && iswhite(v) && !isdead(g,v) && !isdead(g,o));
534	    let g = state.global_mut();
535	    let ow = other_white(g.currentwhite);
536	    debug_assert!(is_black_marked((*o).marked));
537	    debug_assert!(is_white_marked((*v).marked));
538	    debug_assert!(!is_dead_marked(ow, (*v).marked));
539	    debug_assert!(!is_dead_marked(ow, (*o).marked));
