542	    if keep_invariant(g.gcstate) {
543	        // C: reallymarkobject(g, v);
544	        really_mark_object(state, v);
545	        // C: if (isold(o)) { lua_assert(!isold(v)); setage(v, G_OLD0); }
546	        if is_old_marked((*o).marked) {
547	            debug_assert!(!is_old_marked((*v).marked));
548	            (*v).marked = set_age_bits((*v).marked, G_OLD0);
