560	/// C: `void luaC_barrierback_(lua_State *L, GCObject *o)`
561	///
562	/// Backward barrier: re-grays the black object `o` so its references are
563	/// re-examined next propagation.  Used for tables/threads.
564	///
565	/// TODO(port): circular dep — `LuaState` is in lua-vm.
566	pub(crate) unsafe fn barrier_back(
567	    state: &mut LuaState,
568	    o: GcObj,
569	) {
570	    // C: global_State *g = G(L);
571	    // C: lua_assert(isblack(o) && !isdead(g, o));
572	    let g = state.global_mut();
573	    debug_assert!(is_black_marked((*o).marked));
574	    debug_assert!(!is_dead_marked(other_white(g.currentwhite), (*o).marked));
575	    // C: assert (g->gckind == KGC_GEN) == (isold(o) && getage(o) != G_TOUCHED1)
576	    debug_assert_eq!(
577	        g.gckind == KGC_GEN,
578	        is_old_marked((*o).marked) && get_age((*o).marked) != G_TOUCHED1
579	    );
580	
581	    // C: if (getage(o) == G_TOUCHED2) set2gray(o);
582	    // C: else linkobjgclist(o, g->grayagain);
583	    if get_age((*o).marked) == G_TOUCHED2 {
584	        (*o).marked = set_to_gray((*o).marked);
585	    } else {
586	        // PORT NOTE: C uses intrusive gclist; we push to the Vec gray list.
587	        // TODO(port): push raw GcObj to grayagain Vec once Phase D stabilizes.
588	        let gclist = get_gc_list(o);
589	        if !gclist.is_null() {
590	            link_gc_list(o, gclist, &mut g.grayagain);
591	        }
592	    }
593	
594	    // C: if (isold(o)) setage(o, G_TOUCHED1);
595	    if is_old_marked((*o).marked) {
596	        (*o).marked = set_age_bits((*o).marked, G_TOUCHED1);
597	    }
598	}
