/// encountered) or the list is exhausted.
unsafe fn sweep_to_live(state: &mut LuaState, mut p: *mut GcObj) -> *mut GcObj {
    // C: GCObject **old = p; do { p = sweeplist(L, p, 1, NULL); } while (p == old);
