    const NEXT_AGE: [u8; 7] = [
        G_SURVIVAL, G_OLD1, G_OLD1, G_OLD, G_OLD, G_TOUCHED1, G_TOUCHED2,
    ];
    let white = current_white(state.global().currentwhite);

