1868	    // C: sweepgen(L, g, psurvival, g->old1, &g->firstold1);
1869	    // C: g->reallyold=g->old1; g->old1=*psurvival; g->survival=g->allgc;
1870	    state.global_mut().gcstate = GCS_SWP_ALLGC;
1871	    {
