2058	unsafe fn step_gen_full(state: &mut LuaState) {
2059	    // C: lu_mem newatomic; lu_mem lastatomic = g->lastatomic;
2060	    // C: if (g->gckind == KGC_GEN) enterinc(g);
2061	    // C: luaC_runtilstate(L, bitmask(GCSpropagate));
2062	    // C: newatomic = atomic(L);
