2064	    // C: else { g->GCestimate=gettotalbytes; entersweep; runtilstate(pause); setpause; g->lastatomic=newatomic; }
2065	    let lastatomic = state.global().lastatomic;
2066	    if state.global().gckind == KGC_GEN {
2067	        enter_inc(state);
2068	    }
2069	    run_until_state(state, 1u32 << GCS_PROPAGATE);
2070	    let newatomic = atomic_phase(state);
2071	    if newatomic < lastatomic + (lastatomic >> 3) {
2072	        atomic_to_gen(state);
2073	        set_minor_debt(state);
2074	    } else {
2075	        state.global_mut().GCestimate = state.global().total_bytes();
2076	        enter_sweep(state);
2077	        run_until_state(state, 1u32 << GCS_PAUSE);
2078	        set_pause(state);
