    // C: cleargraylists(g);
    clear_gray_lists(state);
    // C: markobject(g, g->mainthread);
    let mainthread = state.global().mainthread_raw();
    if is_white_marked((*mainthread).marked) {
        really_mark_object(state, mainthread);
